import { Sparkles } from "lucide-react";
import { cn } from "@/lib/utils";

// Official brand marks sourced from @lobehub/icons-static-svg and simple-icons.
// All icons use a 24x24 viewBox.

type Brand =
  | "anthropic"
  | "openai"
  | "gemini"
  | "grok"
  | "openrouter"
  | "kimi"
  | "zai"
  | "qwen"
  | "deepseek"
  | "minimax"
  | "bedrock"
  | "azure"
  | "dyad"
  | "ollama"
  | "lmstudio"
  | "custom";

function resolveBrand(providerId: string, apiName?: string): Brand {
  const name = apiName?.toLowerCase() ?? "";

  if (name.startsWith("anthropic/") || name.includes("claude"))
    return "anthropic";
  if (
    name.startsWith("openai/") ||
    name.startsWith("gpt-") ||
    name.startsWith("gpt5")
  )
    return "openai";
  if (name.startsWith("google/") || name.startsWith("gemini")) return "gemini";
  if (name.startsWith("moonshotai/") || name.startsWith("kimi")) return "kimi";
  if (name.startsWith("z-ai/") || name.startsWith("glm-")) return "zai";
  if (name.startsWith("qwen/") || name.startsWith("qwen-")) return "qwen";
  if (name.startsWith("deepseek/") || name.startsWith("deepseek-"))
    return "deepseek";
  if (name.startsWith("minimax/") || name.startsWith("minimax-"))
    return "minimax";
  if (name.startsWith("grok-")) return "grok";

  switch (providerId) {
    case "anthropic":
      return "anthropic";
    case "openai":
      return "openai";
    case "google":
    case "vertex":
      return "gemini";
    case "xai":
      return "grok";
    case "openrouter":
      return "openrouter";
    case "minimax":
      return "minimax";
    case "azure":
      return "azure";
    case "bedrock":
      return "bedrock";
    case "auto":
      return "dyad";
    case "ollama":
      return "ollama";
    case "lmstudio":
      return "lmstudio";
    default:
      return "custom";
  }
}

